function solve(points) {
    const n = points.length;
    const slopeMap = new Map();

    // Helper function to calculate the slope between two points
    function getSlope(p1, p2) {
        const dx = p2[0] - p1[0];
        const dy = p2[1] - p1[1];
        if (dx === 0 && dy === 0) return null; // same point
        if (dx === 0) return Infinity; // vertical line
        return dy / dx;
    }

    // Count the number of pairs with the same slope
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const slope = getSlope(points[i], points[j]);
            if (slope !== null) {
