                if (!slopeMap.has(key)) {
                    slopeMap.set(key, 0);
                }
                slopeMap.set(key, slopeMap.get(key) + 1);
            }
        }
    }

    // Calculate the number of trapezoids
    let count = 0;
    for (const [slope, cnt] of slopeMap.entries()) {
        if (cnt >= 2) {
            // Number of ways to choose 2 pairs with the same slope
            const ways = cnt * (cnt - 1) / 2;
            // Each pair of pairs can form a trapezoid if they share a common point
            count += ways;
        }
    }

    return count;
}

